import React, { useEffect, useState } from "react";
import { Table, Button, Input, Select, Avatar, Tooltip } from "antd";
import {
  Trash2,
  Search,
  Eye,
  Mail,
  Phone,
  MessageSquare,
  Clock,
  CheckCircle2,
  Activity,
  History,
  Send,
} from "lucide-react";
import { useDispatch, useSelector } from "react-redux";
import { Link } from "react-router-dom";
import {
  deleteAEnquiry,
  getEnquiries,
  resetState,
  updateAEnquiry,
} from "../features/enquiry/enquirySlice";
import CustomModal from "../components/CustomModal";

const Enquiries = () => {
  const [open, setOpen] = useState(false);
  const [enqId, setenqId] = useState("");
  const [searchText, setSearchText] = useState("");

  const showModal = (e) => {
    setOpen(true);
    setenqId(e);
  };

  const hideModal = () => {
    setOpen(false);
  };

  const dispatch = useDispatch();
  useEffect(() => {
    dispatch(resetState());
    dispatch(getEnquiries());
  }, [dispatch]);

  const enqState = useSelector((state) => state.enquiry.enquiries);

  const setEnquiryStatus = (e, i) => {
    const data = { id: i, enqData: e };
    dispatch(updateAEnquiry(data));
  };

  const columns = [
    {
      title: "Enquiry ID",
      dataIndex: "key",
      render: (text) => (
        <span className="vibe-pill vibe-pill-muted font-mono">
          ENQ-{String(text).padStart(3, "0")}
        </span>
      ),
    },
    {
      title: "Customer",
      dataIndex: "name",
      render: (text) => (
        <div className="flex items-center gap-3">
          <Avatar
            size={40}
            src={`https://api.dicebear.com/7.x/initials/svg?seed=${text}&backgroundColor=f8fafc&textColor=1e3a8a&bold=true`}
            className="rounded-xl border border-slate-100"
          />
          <div className="flex flex-col">
            <span className="vibe-text-primary text-[15px] font-black tracking-tight leading-none mb-1">
              {text}
            </span>
            <span className="vibe-text-muted text-[12px] font-bold uppercase tracking-wider">
              Patient/Customer
            </span>
          </div>
        </div>
      ),
      sorter: (a, b) => a.name.localeCompare(b.name),
    },
    {
      title: "Contact Info",
      dataIndex: "email",
      render: (text, record) => (
        <div className="flex flex-col gap-1.5">
          <div className="flex items-center gap-2">
            <Mail size={14} className="text-vibe-muted" />
            <span className="vibe-text-primary text-[14px] font-medium">{text}</span>
          </div>
          <div className="flex items-center gap-2">
            <Phone size={14} className="text-vibe-muted" />
            <span className="vibe-text-muted text-[13px] font-semibold">{record.mobile}</span>
          </div>
        </div>
      ),
    },
    {
      title: "Status",
      dataIndex: "status",
      render: (status, record) => (
        <Select
          defaultValue={status ? status : "Submitted"}
          className="w-40 modern-select h-10"
          bordered={false}
          onChange={(e) => setEnquiryStatus(e, record._id)}
          options={[
            {
              value: "Submitted",
              label: (
                <div className="flex items-center gap-2 text-[13px] font-bold text-blue-600">
                  <Send size={14} /> Submitted
                </div>
              ),
            },
            {
              value: "Contacted",
              label: (
                <div className="flex items-center gap-2 text-[13px] font-bold text-amber-600">
                  <Phone size={14} /> Contacted
                </div>
              ),
            },
            {
              value: "In Progress",
              label: (
                <div className="flex items-center gap-2 text-[13px] font-bold text-indigo-600">
                  <Activity size={14} /> In Progress
                </div>
              ),
            },
            {
              value: "Resolved",
              label: (
                <div className="flex items-center gap-2 text-[13px] font-bold text-emerald-600">
                  <CheckCircle2 size={14} /> Resolved
                </div>
              ),
            },
          ]}
        />
      ),
    },
    {
      title: "Actions",
      dataIndex: "action",
      render: (_, record) => (
        <div className="flex items-center gap-2">
          <Link to={`/admin/enquiries/${record._id}`}>
            <Tooltip title="View Message">
              <Button
                type="text"
                icon={<Eye size={18} />}
                className="vibe-action-btn vibe-action-btn-primary"
              />
            </Tooltip>
          </Link>
          <Tooltip title="Delete Enquiry">
            <Button
              type="text"
              icon={<Trash2 size={18} />}
              onClick={() => showModal(record._id)}
              className="vibe-action-btn vibe-action-btn-danger"
            />
          </Tooltip>
        </div>
      ),
    },
  ];

  const data1 =
    enqState
      ?.filter(
        (e) =>
          !searchText ||
          e.name.toLowerCase().includes(searchText.toLowerCase()) ||
          e.email.toLowerCase().includes(searchText.toLowerCase()),
      )
      .map((enq, i) => ({
        key: i + 1,
        _id: enq._id,
        name: enq.name,
        email: enq.email,
        mobile: enq.mobile,
        status: enq.status,
      })) || [];

  const deleteEnq = (e) => {
    dispatch(deleteAEnquiry(e));
    setOpen(false);
    setTimeout(() => {
      dispatch(getEnquiries());
    }, 100);
  };

  return (
    <div className="space-y-8 pb-12">
      {/* Header Section */}
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="vibe-h1">
            Customer Enquiries
          </h1>
          <p className="vibe-text-muted text-[15px] font-bold mt-1">
            Manage patient questions, support requests, and prescription queries.
          </p>
        </div>
        <div className="relative w-full sm:w-80">
          <Search
            className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"
            size={18}
          />
          <input
            type="text"
            placeholder="Search enquiries..."
            className="vibe-input pl-10"
            onChange={(e) => setSearchText(e.target.value)}
          />
        </div>
      </div>

      <div className="vibe-card !p-0 overflow-hidden">
        <div className="flex items-center gap-4 p-8 border-b border-white/5 bg-white/5 dark:bg-white/5">
          <div className="vibe-icon-box vibe-icon-box-primary">
            <MessageSquare size={20} />
          </div>
          <div>
            <span className="vibe-text-primary text-[15px] font-black border-white/10 pr-4 mr-4 border-r uppercase tracking-tighter">
              Active Archive
            </span>
            <span className="vibe-text-muted text-[14px] font-bold italic">
              Showing <span className="text-accent">{data1.length}</span> patient messages
            </span>
          </div>
        </div>

        <Table
          columns={columns}
          dataSource={data1}
          pagination={{
            pageSize: 10,
            className: "px-6 py-4",
          }}
          className="vibe-table"
        />
      </div>

      <CustomModal
        hideModal={hideModal}
        open={open}
        performAction={() => deleteEnq(enqId)}
        title="Delete Enquiry"
        content="Are you sure you want to delete this enquiry? This action will permanently remove the record."
      />

      <style>{`
        .modern-select .ant-select-selector {
          background: #f8fafc !important;
          border-radius: 12px !important;
          border: 1px solid #e2e8f0 !important;
          padding: 0 12px !important;
          display: flex !important;
          align-items: center !important;
        }
        .modern-table .ant-table-thead > tr > th {
          background: #fff !important;
          font-weight: 700 !important;
          font-size: 14px !important;
          color: #64748b !important;
          text-transform: uppercase !important;
          letter-spacing: 0.05em !important;
          border-bottom: 2px solid #f1f5f9 !important;
          padding: 16px 24px !important;
        }
        .modern-table .ant-table-tbody > tr > td {
          padding: 20px 24px !important;
          border-bottom: 1px solid #f8fafc !important;
        }
      `}</style>
    </div>
  );
};

export default Enquiries;
